#!/usr/bin/env python3
"""
Brainfuck Canvas Runner
Usage: python bf_canvas.py program.bf

Syntax:
  |+++>+++|   header: cols x rows (count + on each side of >)
  |           paint current pixel with cells[ptr] (0-255 = color from palette)

Color palette (0-255):
  0          = black
  1-31       = red → yellow
  32-63      = yellow → green
  64-95      = green → cyan
  96-127     = cyan → blue
  128-159    = blue → magenta
  160-191    = magenta → red
  192-223    = bright whites / pastels
  224-254    = grays
  255        = white
"""

import sys
import colorsys
import pygame

BLOCK = 50
CELLS = 30000

# build palette: 256 RGB colors
PALETTE = [(0, 0, 0)] * 256
PALETTE[0] = (0, 0, 0)          # black
PALETTE[255] = (255, 255, 255)  # white

# 1-191: full hue wheel (red→yellow→green→cyan→blue→magenta→red)
for i in range(1, 192):
    h = (i - 1) / 191.0
    r, g, b = colorsys.hsv_to_rgb(h, 1.0, 1.0)
    PALETTE[i] = (int(r * 255), int(g * 255), int(b * 255))

# 192-223: pastel (high brightness, low saturation)
for i in range(192, 224):
    h = (i - 192) / 32.0
    r, g, b = colorsys.hsv_to_rgb(h, 0.4, 1.0)
    PALETTE[i] = (int(r * 255), int(g * 255), int(b * 255))

# 224-254: dark → light gray
for i in range(224, 255):
    v = int((i - 224) / 30.0 * 200) + 40
    PALETTE[i] = (v, v, v)


def parse(source):
    s = source.strip()
    if s.startswith("|"):
        end = s.index("|", 1)
        header = s[1:end]
        body = s[end+1:]
        left, _, right = header.partition(">")
        cols = left.count("+") or 1
        rows = right.count("+") or 1
    else:
        cols, rows = 8, 8
        body = s
    code = "".join(c for c in body if c in set('><+-.,[]|'))
    return cols, rows, code

def build_loops(code):
    lm, stack = {}, []
    for i, c in enumerate(code):
        if c == "[": stack.append(i)
        elif c == "]":
            s = stack.pop()
            lm[s] = i; lm[i] = s
    return lm

def run(code, cells, lm):
    ptr, i = 0, 0
    while i < len(code):
        c = code[i]
        if   c == ">": ptr = (ptr + 1) % CELLS
        elif c == "<": ptr = (ptr - 1) % CELLS
        elif c == "+": cells[ptr] = (cells[ptr] + 1) % 256
        elif c == "-": cells[ptr] = (cells[ptr] - 1) % 256
        elif c == ".": print(chr(cells[ptr]), end="", flush=True)
        elif c == ",":
            print("> ", end="", flush=True)
            ch = sys.stdin.read(1)
            cells[ptr] = ord(ch) if ch else 0
        elif c == "[" and cells[ptr] == 0: i = lm[i]
        elif c == "]" and cells[ptr] != 0: i = lm[i]
        elif c == "|": yield ptr
        i += 1

def draw(screen, cells, cols, rows, font):
    screen.fill((18, 18, 18))
    for idx in range(cols * rows):
        col = idx % cols
        row = idx // cols
        v = cells[idx] if idx < CELLS else 0
        color = PALETTE[v]
        rect = (col * BLOCK, row * BLOCK, BLOCK, BLOCK)
        pygame.draw.rect(screen, color, rect)
        pygame.draw.rect(screen, (40, 40, 40), rect, 1)
    # hover
    mx, my = pygame.mouse.get_pos()
    px, py = mx // BLOCK, my // BLOCK
    if 0 <= px < cols and 0 <= py < rows:
        idx = py * cols + px
        v = cells[idx] if idx < CELLS else 0
        c = PALETTE[v]
        label = f"({px},{py}) val={v}  rgb{c}"
        txt = font.render(label, True, (220, 220, 220))
        bg = pygame.Surface((txt.get_width() + 6, txt.get_height() + 4))
        bg.fill((20, 20, 20))
        by = py * BLOCK - 22 if py == rows - 1 else py * BLOCK + BLOCK + 2
        screen.blit(bg, (2, by))
        screen.blit(txt, (5, by + 2))

def main():
    if len(sys.argv) >= 2:
        with open(sys.argv[1]) as f:
            source = f.read()
    else:
        # demo: 8x4 gradient across the palette
        source = """
|++++++++++++++++>++++++++++++++++|
->-->--->---->----->------>------->-------->--------->---------->----------->------------>------------->-------------->--------------->---------------->----------------->------------------>------------------->-------------------->--------------------->---------------------->----------------------->------------------------>------------------------->-------------------------->--------------------------->---------------------------->----------------------------->------------------------------>------------------------------->-------------------------------->--------------------------------->---------------------------------->----------------------------------->------------------------------------>------------------------------------->-------------------------------------->--------------------------------------->---------------------------------------->----------------------------------------->------------------------------------------>------------------------------------------->-------------------------------------------->--------------------------------------------->---------------------------------------------->----------------------------------------------->------------------------------------------------>------------------------------------------------->-------------------------------------------------->--------------------------------------------------->---------------------------------------------------->----------------------------------------------------->------------------------------------------------------>------------------------------------------------------->-------------------------------------------------------->--------------------------------------------------------->---------------------------------------------------------->----------------------------------------------------------->------------------------------------------------------------>------------------------------------------------------------->-------------------------------------------------------------->--------------------------------------------------------------->---------------------------------------------------------------->----------------------------------------------------------------->------------------------------------------------------------------>------------------------------------------------------------------->-------------------------------------------------------------------->--------------------------------------------------------------------->---------------------------------------------------------------------->----------------------------------------------------------------------->------------------------------------------------------------------------>------------------------------------------------------------------------->-------------------------------------------------------------------------->--------------------------------------------------------------------------->---------------------------------------------------------------------------->----------------------------------------------------------------------------->------------------------------------------------------------------------------>------------------------------------------------------------------------------->-------------------------------------------------------------------------------->--------------------------------------------------------------------------------->---------------------------------------------------------------------------------->----------------------------------------------------------------------------------->------------------------------------------------------------------------------------>------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------>------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------->--------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------"""
        print("No file given — running built-in palette demo.")

    cols, rows, code = parse(source)
    cells = [0] * CELLS
    lm = build_loops(code)

    for _ in run(code, cells, lm):
        pass

    pygame.init()
    screen = pygame.display.set_mode((cols * BLOCK, rows * BLOCK))
    pygame.display.set_caption("bf canvas")
    font = pygame.font.SysFont("monospace", 13)
    clock = pygame.time.Clock()

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key in (pygame.K_q, pygame.K_ESCAPE):
                    running = False
                elif event.key == pygame.K_r:
                    cells = [0] * CELLS
                    for _ in run(code, cells, lm):
                        pass

        draw(screen, cells, cols, rows, font)
        pygame.display.flip()
        clock.tick(60)

    pygame.quit()

if __name__ == "__main__":
    main()